+/**
+ * SMS notification adapter — delivers notifications via SMS.
+ *
+ * Implements the NotificationAdapter interface with:
+ * - Phone number validation
+ * - Message formatting (subject + body, truncated to SMS length)
+ * - Configurable retry logic
+ * - Delivery tracking with sent message log
+ *
+ * In production, swap the transport layer via `setTransport()` for a real
+ * provider (Twilio, AWS SNS, etc.). The adapter contract stays the same.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/** Configuration for the SMS adapter. */
+export interface SmsAdapterConfig {
+  /** Sender ID or phone number shown as the sender. */
+  fromNumber: string;
+  /** Maximum SMS message length (standard is 160 for single-segment). */
+  maxMessageLength: number;
+  /** Number of retry attempts on transient failures. */
+  maxRetries: number;
+}
+
+const DEFAULT_CONFIG: SmsAdapterConfig = {
+  fromNumber: '+10000000000',
+  maxMessageLength: 160,
+  maxRetries: 2,
+};
+
+/** Record of a sent SMS message. */
+export interface SentSms {
+  to: string;
+  from: string;
+  message: string;
+  sentAt: Date;
+  attempts: number;
+}
+
+/**
+ * Validates a phone number format.
+ * Accepts E.164 format: + followed by 7-15 digits.
+ * Returns an error string or null if valid.
+ */
+export function validatePhoneNumber(phone: string): string | null {
+  if (!phone || phone.trim() === '') {
+    return 'Recipient phone number is required';
+  }
+  // E.164: + followed by 7–15 digits
+  if (!/^\+[1-9]\d{6,14}$/.test(phone.trim())) {
+    return 'Invalid phone number format (expected E.164, e.g. +14155551234)';
+  }
+  return null;
+}
+
+export class SmsAdapter implements NotificationAdapter {
+  readonly channel: NotificationChannel = 'sms';
+  private logger = new Logger('SmsAdapter');
+  private config: SmsAdapterConfig;
+  private sentMessages: SentSms[] = [];
+  /** Optional hook to simulate transport failures in tests. */
+  private transportFn: ((sms: SentSms) => Promise<boolean>) | null = null;
+
+  constructor(config?: Partial<SmsAdapterConfig>) {
+    this.config = { ...DEFAULT_CONFIG, ...config };
+  }
+
+  // ---------------------------------------------------------------------------
+  // NotificationAdapter interface
+  // ---------------------------------------------------------------------------
+
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    // 1. Validate recipient phone number
+    const phoneError = validatePhoneNumber(payload.recipient);
+    if (phoneError) {
+      this.logger.error(`Invalid recipient "${payload.recipient}": ${phoneError}`);
+      return { success: false, channel: this.channel, error: phoneError };
+    }
+
+    // 2. Format the SMS message
+    const message = this.formatMessage(payload);
+
+    // 3. Attempt delivery (with retries)
+    const sms: SentSms = {
+      to: payload.recipient,
+      from: this.config.fromNumber,
+      message,
+      sentAt: new Date(),
+      attempts: 0,
+    };
+
+    const maxAttempts = this.config.maxRetries + 1;
+    let lastError: string | undefined;
+
+    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
+      sms.attempts = attempt;
+      try {
+        const ok = await this.sendSms(sms);
+        if (ok) {
+          this.sentMessages.push(sms);
+          this.logger.info(`SMS sent to ${payload.recipient} (attempt ${attempt})`);
+          return { success: true, channel: this.channel };
+        }
+        lastError = 'SMS provider returned failure';
+      } catch (err) {
+        lastError = err instanceof Error ? err.message : String(err);
+        this.logger.warn(
+          `SMS delivery attempt ${attempt}/${maxAttempts} failed for ${payload.recipient}: ${lastError}`,
+        );
+      }
+    }
+
+    // All retries exhausted
+    this.logger.error(`SMS delivery failed for ${payload.recipient} after ${maxAttempts} attempts: ${lastError}`);
+    return { success: false, channel: this.channel, error: lastError };
+  }
+
+  // ---------------------------------------------------------------------------
+  // Message formatting
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Format the notification payload into a plain-text SMS message.
+   * Truncates to maxMessageLength if necessary.
+   */
+  private formatMessage(payload: NotificationPayload): string {
+    const full = `${payload.subject}: ${payload.body}`;
+    if (full.length <= this.config.maxMessageLength) {
+      return full;
+    }
+    // Truncate with ellipsis
+    return full.substring(0, this.config.maxMessageLength - 3) + '...';
+  }
+
+  // ---------------------------------------------------------------------------
+  // Transport layer
+  // ---------------------------------------------------------------------------
+
+  /**
+   * Internal SMS transport. By default this always succeeds (in-memory).
+   * In production replace with a real SMS API call (Twilio, SNS, etc.).
+   * Use `setTransport()` in tests to simulate failures.
+   */
+  private async sendSms(sms: SentSms): Promise<boolean> {
+    if (this.transportFn) {
+      return this.transportFn(sms);
+    }
+    // Default: successful in-memory delivery
+    return true;
+  }
+
+  /**
+   * Override the internal transport function. Useful in tests to simulate
+   * transient failures, permanent failures, or latency.
+   */
+  setTransport(fn: (sms: SentSms) => Promise<boolean>): void {
+    this.transportFn = fn;
+  }
+
+  // ---------------------------------------------------------------------------
+  // Inspection helpers (testing / debugging)
+  // ---------------------------------------------------------------------------
+
+  getSentMessages(): SentSms[] {
+    return [...this.sentMessages];
+  }
+
+  clearSentMessages(): void {
+    this.sentMessages = [];
+  }
+
+  getConfig(): SmsAdapterConfig {
+    return { ...this.config };
+  }
+}

