+import { describe, it, expect, beforeEach } from 'vitest';
+import { SmsAdapter, validatePhoneNumber } from '../../src/adapters/sms.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+describe('SmsAdapter', () => {
+  let adapter: SmsAdapter;
+
+  beforeEach(() => {
+    adapter = new SmsAdapter({ fromNumber: '+15551234567' });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Basic send
+  // ---------------------------------------------------------------------------
+
+  describe('send', () => {
+    it('should successfully send an SMS', async () => {
+      const payload: NotificationPayload = {
+        type: 'order_confirmation',
+        recipient: '+14155559999',
+        subject: 'Order Confirmation',
+        body: 'Your order has been placed.',
+        metadata: { orderId: 'order-1', userId: 'user-1' },
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('sms');
+      expect(result.error).toBeUndefined();
+    });
+
+    it('should store sent message with correct fields', async () => {
+      const payload: NotificationPayload = {
+        type: 'order_confirmation',
+        recipient: '+14155559999',
+        subject: 'Order Confirmation',
+        body: 'Your order has been placed.',
+      };
+
+      await adapter.send(payload);
+
+      const messages = adapter.getSentMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]?.to).toBe('+14155559999');
+      expect(messages[0]?.from).toBe('+15551234567');
+      expect(messages[0]?.message).toBe('Order Confirmation: Your order has been placed.');
+      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
+      expect(messages[0]?.attempts).toBe(1);
+    });
+
+    it('should report channel as sms', () => {
+      expect(adapter.channel).toBe('sms');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Phone number validation
+  // ---------------------------------------------------------------------------
+
+  describe('phone number validation', () => {
+    it('should reject empty recipient', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '',
+        subject: 'Welcome',
+        body: 'Hello!',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('required');
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should reject invalid phone format', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: 'not-a-phone',
+        subject: 'Welcome',
+        body: 'Hello!',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid phone number');
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should reject phone without country code', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '4155551234',
+        subject: 'Welcome',
+        body: 'Hello!',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('E.164');
+    });
+
+    it('should reject phone with letters', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+1415abc1234',
+        subject: 'Welcome',
+        body: 'Hello!',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid phone number');
+    });
+
+    it('should accept valid E.164 phone number', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Welcome',
+        body: 'Hello!',
+      });
+
+      expect(result.success).toBe(true);
+    });
+
+    it('should accept international phone numbers', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+447911123456',
+        subject: 'Welcome',
+        body: 'Hello!',
+      });
+
+      expect(result.success).toBe(true);
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // validatePhoneNumber utility
+  // ---------------------------------------------------------------------------
+
+  describe('validatePhoneNumber', () => {
+    it('should return null for valid E.164 numbers', () => {
+      expect(validatePhoneNumber('+14155551234')).toBeNull();
+      expect(validatePhoneNumber('+447911123456')).toBeNull();
+      expect(validatePhoneNumber('+8613800138000')).toBeNull();
+    });
+
+    it('should return error for empty string', () => {
+      expect(validatePhoneNumber('')).toContain('required');
+    });
+
+    it('should return error for non-E.164 format', () => {
+      expect(validatePhoneNumber('4155551234')).toContain('E.164');
+      expect(validatePhoneNumber('+0123456')).toContain('E.164');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Message formatting
+  // ---------------------------------------------------------------------------
+
+  describe('message formatting', () => {
+    it('should format message as "subject: body"', async () => {
+      let capturedSms: { message: string } | undefined;
+      adapter.setTransport(async (sms) => {
+        capturedSms = sms;
+        return true;
+      });
+
+      await adapter.send({
+        type: 'order_status_update',
+        recipient: '+14155551234',
+        subject: 'Order Update',
+        body: 'Your order has shipped.',
+      });
+
+      expect(capturedSms?.message).toBe('Order Update: Your order has shipped.');
+    });
+
+    it('should truncate long messages to maxMessageLength', async () => {
+      const shortAdapter = new SmsAdapter({ maxMessageLength: 30 });
+      let capturedSms: { message: string } | undefined;
+      shortAdapter.setTransport(async (sms) => {
+        capturedSms = sms;
+        return true;
+      });
+
+      await shortAdapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Welcome to TaskFlow Pro',
+        body: 'We are glad to have you on board!',
+      });
+
+      expect(capturedSms?.message).toHaveLength(30);
+      expect(capturedSms?.message).toMatch(/\.\.\.$/);
+    });
+
+    it('should not truncate messages within limit', async () => {
+      let capturedSms: { message: string } | undefined;
+      adapter.setTransport(async (sms) => {
+        capturedSms = sms;
+        return true;
+      });
+
+      await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Hi',
+        body: 'Hello!',
+      });
+
+      expect(capturedSms?.message).toBe('Hi: Hello!');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Configuration
+  // ---------------------------------------------------------------------------
+
+  describe('configuration', () => {
+    it('should use default config when none provided', () => {
+      const defaultAdapter = new SmsAdapter();
+      const config = defaultAdapter.getConfig();
+      expect(config.fromNumber).toBe('+10000000000');
+      expect(config.maxMessageLength).toBe(160);
+      expect(config.maxRetries).toBe(2);
+    });
+
+    it('should accept custom config overrides', () => {
+      const custom = new SmsAdapter({
+        fromNumber: '+18005551234',
+        maxMessageLength: 320,
+        maxRetries: 5,
+      });
+
+      const config = custom.getConfig();
+      expect(config.fromNumber).toBe('+18005551234');
+      expect(config.maxMessageLength).toBe(320);
+      expect(config.maxRetries).toBe(5);
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Retry logic
+  // ---------------------------------------------------------------------------
+
+  describe('retry logic', () => {
+    it('should retry on transport failure', async () => {
+      let callCount = 0;
+      adapter.setTransport(async () => {
+        callCount++;
+        if (callCount < 3) {
+          throw new Error('Network timeout');
+        }
+        return true;
+      });
+
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result.success).toBe(true);
+      expect(callCount).toBe(3);
+      expect(adapter.getSentMessages()[0]?.attempts).toBe(3);
+    });
+
+    it('should fail after all retries exhausted', async () => {
+      adapter.setTransport(async () => {
+        throw new Error('Permanent failure');
+      });
+
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Permanent failure');
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should fail when transport returns false', async () => {
+      adapter.setTransport(async () => false);
+
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('SMS provider returned failure');
+    });
+
+    it('should respect maxRetries config', async () => {
+      const noRetry = new SmsAdapter({ maxRetries: 0 });
+      let callCount = 0;
+      noRetry.setTransport(async () => {
+        callCount++;
+        throw new Error('fail');
+      });
+
+      await noRetry.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(callCount).toBe(1);
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Inspection helpers
+  // ---------------------------------------------------------------------------
+
+  describe('inspection helpers', () => {
+    it('should clear sent messages', async () => {
+      await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(adapter.getSentMessages()).toHaveLength(1);
+      adapter.clearSentMessages();
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should return a copy of sent messages', async () => {
+      await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      const messages1 = adapter.getSentMessages();
+      const messages2 = adapter.getSentMessages();
+      expect(messages1).not.toBe(messages2);
+      expect(messages1).toEqual(messages2);
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // NotificationAdapter interface compliance
+  // ---------------------------------------------------------------------------
+
+  describe('NotificationAdapter interface compliance', () => {
+    it('should have a channel property', () => {
+      expect(adapter.channel).toBe('sms');
+    });
+
+    it('should have an async send method that returns NotificationResult', async () => {
+      const result = await adapter.send({
+        type: 'welcome',
+        recipient: '+14155551234',
+        subject: 'Test',
+        body: 'Hello',
+      });
+
+      expect(result).toHaveProperty('success');
+      expect(result).toHaveProperty('channel');
+      expect(typeof result.success).toBe('boolean');
+      expect(result.channel).toBe('sms');
+    });
+  });
+
+  // ---------------------------------------------------------------------------
+  // Registration with NotificationService
+  // ---------------------------------------------------------------------------
+
+  describe('registration with NotificationService', () => {
+    it('should be registrable with notification service', async () => {
+      const { EventBus } = await import('../../src/events/event-bus.js');
+      const { NotificationService } = await import('../../src/services/notification.service.js');
+
+      const eventBus = new EventBus();
+      const notificationService = new NotificationService(eventBus);
+
+      // Should not throw when registering
+      notificationService.registerAdapter(adapter);
+
+      // Trigger via event — recipient is the user's email in the event, but
+      // for SMS the adapter will validate and fail (email != phone).
+      // This test verifies registration and dispatch, not successful delivery.
+      await eventBus.emit({
+        type: 'order:created',
+        timestamp: new Date(),
+        order: {
+          id: 'order-99',
+          userId: 'user-1',
+          items: [{ productId: 'p1', name: 'Widget', quantity: 1, price: 10 }],
+          total: 10,
+          status: 'pending',
+          createdAt: new Date(),
+          updatedAt: new Date(),
+        },
+        user: { id: 'user-1', email: '+14155551234', name: 'Test User', createdAt: new Date(), updatedAt: new Date() },
+      });
+
+      const messages = adapter.getSentMessages();
+      expect(messages.length).toBeGreaterThanOrEqual(1);
+
+      const notifications = notificationService.getNotifications();
+      const smsNotifs = notifications.filter((n) => n.channel === 'sms');
+      expect(smsNotifs.length).toBeGreaterThanOrEqual(1);
+    });
+  });
+});

